import React, { useState, useRef } from 'react';

const FileUpload = ({ onFileProcessed, theme, isLoading: parentLoading, sessionId }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploadError, setUploadError] = useState(null);
  const fileInputRef = useRef(null);

  const supportedTypes = [
    'application/pdf',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    'application/vnd.ms-excel',
    'application/vnd.openxmlformats-officedocument.presentationml.presentation',
    'application/vnd.ms-powerpoint',
    'text/plain',
    'image/jpeg',
    'image/png',
    'image/gif',
    'image/bmp',
    'image/tiff',
    'image/webp'
  ];

  const handleFiles = async (files) => {
    const file = files[0];
    if (!file) return;

    setUploadError(null);

    // Enhanced file validation
    if (!supportedTypes.includes(file.type)) {
      setUploadError(`File type "${file.type}" not supported! Please upload PDF, Word, Excel, PowerPoint, or image files.`);
      return;
    }

    if (file.size > 16 * 1024 * 1024) {
      setUploadError(`File size ${(file.size / (1024 * 1024)).toFixed(2)}MB is too large! Please upload files smaller than 16MB.`);
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);

    try {
      const formData = new FormData();
      formData.append('file', file);

      // Enhanced progress simulation
      const progressInterval = setInterval(() => {
        setUploadProgress(prev => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return 90;
          }
          return prev + Math.random() * 15; // More realistic progress
        });
      }, 150);

      // Make request to Flask backend with proper error handling
      const response = await fetch('/api/files/upload', {
        method: 'POST',
        body: formData,
        // Add headers for better compatibility
        headers: {
          // Don't set Content-Type - let browser set it with boundary
        },
      });

      clearInterval(progressInterval);
      setUploadProgress(100);

      // Enhanced response handling
      if (!response.ok) {
        if (response.status === 404) {
          throw new Error('File upload endpoint not found. Make sure your backend server is running on port 5000 and proxy is configured.');
        } else if (response.status === 413) {
          throw new Error('File too large for server processing.');
        } else if (response.status >= 500) {
          throw new Error('Server error. Please try again later.');
        } else {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
      }

      let result;
      try {
        result = await response.json();
      } catch (parseError) {
        throw new Error('Invalid response from server. Please check your backend.');
      }

      if (result.success) {
        onFileProcessed(result);
        setUploadError(null);
        console.log(`✅ File "${file.name}" processed successfully by Nexus!`);
      } else {
        throw new Error(result.error || 'Upload failed - unknown error');
      }

    } catch (error) {
      console.error('File upload error:', error);
      
      // Enhanced error messages for better debugging
      let errorMessage = error.message;
      
      if (error.message.includes('Failed to fetch')) {
        errorMessage = 'Cannot connect to server. Make sure your Flask backend is running on port 5000 and proxy is configured in package.json.';
      } else if (error.message.includes('404')) {
        errorMessage = 'Upload endpoint not found. Check if your backend routes are properly registered.';
      }
      
      setUploadError(errorMessage);
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFiles(e.dataTransfer.files);
    }
  };

  const handleInputChange = (e) => {
    if (e.target.files && e.target.files[0]) {
      handleFiles(e.target.files);
    }
  };

  const openFileDialog = () => {
    if (!isDisabled) {
      fileInputRef.current?.click();
    }
  };

  // Clear error when user starts new upload
  const clearError = () => {
    setUploadError(null);
  };

  const isDisabled = isUploading || parentLoading;

  return (
    <div className={`file-upload-container ${theme}`}>
      <input
        ref={fileInputRef}
        type="file"
        onChange={handleInputChange}
        accept=".pdf,.docx,.doc,.xlsx,.xls,.pptx,.ppt,.txt,.jpg,.jpeg,.png,.gif,.bmp,.tiff,.webp"
        style={{ display: 'none' }}
        disabled={isDisabled}
      />

      <button
        className="file-upload-btn"
        onClick={openFileDialog}
        disabled={isDisabled}
        title={isUploading ? "Uploading..." : "Upload files (PDF, Word, Excel, PowerPoint, Images)"}
      >
        {isUploading ? (
          <div className="upload-progress">
            <div className="progress-ring">
              <svg width="18" height="18">
                <circle 
                  cx="9" cy="9" r="7" 
                  stroke="currentColor" 
                  strokeWidth="2" 
                  fill="none"
                  strokeDasharray="44"
                  strokeDashoffset={44 - (44 * uploadProgress) / 100}
                  style={{ transition: 'stroke-dashoffset 0.3s' }}
                />
              </svg>
            </div>
          </div>
        ) : (
          <span className="upload-icon">📎</span>
        )}
      </button>

      {/* Enhanced Error Display */}
      {uploadError && (
        <div className="upload-error">
          <span className="error-icon">⚠️</span>
          <div className="error-content">
            <span className="error-text">{uploadError}</span>
            <button 
              className="error-close"
              onClick={clearError}
              title="Close error"
            >
              ✕
            </button>
          </div>
        </div>
      )}

      {/* Enhanced Drag and Drop Overlay */}
      <div
        className={`drag-drop-overlay ${dragActive ? 'active' : ''}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <div className="drag-drop-content">
          <div className="drag-animation">
            <div className="drag-icon">📁</div>
            <div className="drag-ripple"></div>
          </div>
          <h3>Drop your files here</h3>
          <p className="drag-subtitle">Let Nexus analyze your documents</p>
          <div className="supported-formats">
            <span>📄 PDF</span>
            <span>📝 Word</span>
            <span>📊 Excel</span>
            <span>📽️ PowerPoint</span>
            <span>🖼️ Images</span>
          </div>
          <p className="file-limit">Max size: 16MB</p>
        </div>
      </div>
    </div>
  );
};

export default FileUpload;
